   230	// applyJSONPatch applies the override on to the given unstructured object.
   231	func applyJSONPatch(obj *unstructured.Unstructured, overrides []overrideOption) error {
   232		jsonPatchBytes, err := json.Marshal(overrides)
   233		if err != nil {
   234			return err
   235		}
   236	
   237		patch, err := jsonpatch.DecodePatch(jsonPatchBytes)
   238		if err != nil {
   239			return err
   240		}
   241	
   242		objectJSONBytes, err := obj.MarshalJSON()
   243		if err != nil {
   244			return err
   245		}
   246	
   247		patchedObjectJSONBytes, err := patch.Apply(objectJSONBytes)
   248		if err != nil {
   249			return err
   250		}
   251	
   252		err = obj.UnmarshalJSON(patchedObjectJSONBytes)
   253		return err
   254	}
   255	
   256	// applyRawJSONPatch applies the override on to the given raw json object.
   257	func applyRawJSONPatch(raw []byte, overrides []overrideOption) ([]byte, error) {
