   275			return nil, err
   276		}
   277	
   278		jsonPatchBytes, err := json.Marshal(overrides)
   279		if err != nil {
   280			return nil, err
   281		}
   282	
   283		patch, err := jsonpatch.DecodePatch(jsonPatchBytes)
   284		if err != nil {
   285			return nil, err
   286		}
   287	
   288		rawJSON, err = patch.Apply(rawJSON)
   289		if err != nil {
   290			return nil, err
   291		}
   292	
   293		rawYAML, err := yaml.JSONToYAML(rawJSON)
   294		if err != nil {
   295			klog.Errorf("Failed to convert json to yaml, error: %v", err)
