   302	// applyPolicyOverriders applies OverridePolicy/ClusterOverridePolicy overriders to target object
   303	func applyPolicyOverriders(rawObj *unstructured.Unstructured, overriders policyv1alpha1.Overriders) error {
   304		err := applyImageOverriders(rawObj, overriders.ImageOverrider)
   305		if err != nil {
   306			return err
   307		}
   308		// patch command
   309		if err := applyCommandOverriders(rawObj, overriders.CommandOverrider); err != nil {
   310			return err
   311		}
   312		// patch args
   313		if err := applyArgsOverriders(rawObj, overriders.ArgsOverrider); err != nil {
   314			return err
   315		}
   316		if err := applyLabelsOverriders(rawObj, overriders.LabelsOverrider); err != nil {
   317			return err
   318		}
   319		if err := applyAnnotationsOverriders(rawObj, overriders.AnnotationsOverrider); err != nil {
   320			return err
   321		}
   322		if err := applyFieldOverriders(rawObj, overriders.FieldOverrider); err != nil {
   323			return err
   324		}
   325		return applyJSONPatch(rawObj, parseJSONPatchesByPlaintext(overriders.Plaintext))
   326	}
