   377	func applyFieldOverriders(rawObj *unstructured.Unstructured, FieldOverriders []policyv1alpha1.FieldOverrider) error {
   378		if len(FieldOverriders) == 0 {
   379			return nil
   380		}
   381		for index := range FieldOverriders {
   382			pointer, err := jsonpointer.New(FieldOverriders[index].FieldPath)
   383			if err != nil {
   384				klog.Errorf("Build jsonpointer with overrider's path err: %v", err)
   385				return err
   386			}
   387			res, kind, err := pointer.Get(rawObj.Object)
   388			if err != nil {
   389				klog.Errorf("Get value by overrider's path err: %v", err)
   390				return err
   391			}
   392			if kind != reflect.String {
   393				errMsg := fmt.Sprintf("Get object's value by overrider's path(%s) is not string", FieldOverriders[index].FieldPath)
   394				klog.Error(errMsg)
   395				return errors.New(errMsg)
   396			}
   397			dataBytes := []byte(res.(string))
   398			klog.V(4).Infof("Parsed JSON patches by FieldOverriders[%d](%+v)", index, FieldOverriders[index])
   399			var appliedRawData []byte
   400			if len(FieldOverriders[index].YAML) > 0 {
   401				appliedRawData, err = applyRawYAMLPatch(dataBytes, parseYAMLPatchesByField(FieldOverriders[index].YAML))
   402				if err != nil {
   403					klog.Errorf("Error applying raw JSON patch: %v", err)
   404					return err
   405				}
   406			} else if len(FieldOverriders[index].JSON) > 0 {
   407				appliedRawData, err = applyRawJSONPatch(dataBytes, parseJSONPatchesByField(FieldOverriders[index].JSON))
   408				if err != nil {
   409					klog.Errorf("Error applying raw YAML patch: %v", err)
   410					return err
   411				}
   412			}
   413			_, err = pointer.Set(rawObj.Object, string(appliedRawData))
   414			if err != nil {
   415				return err
   416			}
   417		}
   418		return nil
   419	}
