   421	func parseJSONPatchesByPlaintext(overriders []policyv1alpha1.PlaintextOverrider) []overrideOption {
   422		patches := make([]overrideOption, 0, len(overriders))
   423		for i := range overriders {
   424			patches = append(patches, overrideOption{
   425				Op:    string(overriders[i].Operator),
   426				Path:  overriders[i].Path,
   427				Value: overriders[i].Value,
   428			})
   429		}
   430		return patches
   431	}
